examples.good:
function Session() {
  const [warn, setWarn] = useState(false);
  useEffect(() => {
    const t = setTimeout(() => setWarn(true), 29 * 60 * 1000);
    return () => clearTimeout(t);
  }, []);
  return (
    <main>
      {warn && (
        <div role="alertdialog" aria-label="Session bientôt expirée">
          <p>Votre session expire dans 1 minute.</p>
          <button type="button" onClick={extendSession}>Prolonger</button>
        </div>
      )}
    </main>
  );
}

